class Solution:
    def minimumCost(self, target: str, words: List[str], costs: List[int]) -> int:
        import heapq

        n = len(target)
        dp = [float('inf')] * (n + 1)
        dp[0] = 0

        for i in range(n):
            if dp[i] == float('inf'):
                continue
            for j in range(len(words)):
                word = words[j]
                cost = costs[j]
                l = len(word)
                if i + l <= n and target[i:i+l] == word:
                    if dp[i + l] > dp[i] + cost:
                        dp[i + l] = dp[i] + cost

        return dp[n] if dp[n] != float('inf') else -1
